"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[341893],{302145:e=>{e.exports=JSON.parse('{"tag":{"label":"decoration","permalink":"/dst-api-webdocs/docs/tags/decoration","allTagsPath":"/dst-api-webdocs/docs/tags","count":56,"items":[{"id":"game-scripts/prefabs/alterguardian_hat_equipped","title":"Alterguardian Hat Equipped","description":"Renders and manages the visual representation of the Alterguardian\'s equipped hat, including flame and snow effects, with animation state and skinning support.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/alterguardian_hat_equipped"},{"id":"game-scripts/prefabs/atrium_rubble","title":"Atrium Rubble","description":"A decorative, non-interactive rubble prop used in the Atrium environment that supports animated variants and story-line based scrapbook status.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/atrium_rubble"},{"id":"game-scripts/prefabs/balloonparty","title":"Balloonparty","description":"A party-themed decorative balloon that grants nearby players periodic sanity recovery when active in the world, with associated confetti effects and a debuff buff that scales with party size.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balloonparty"},{"id":"game-scripts/prefabs/boatlip","title":"Boatlip","description":"A visual, non-physical ground-decor entity used to animate boat lips at waterline transitions in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatlip"},{"id":"game-scripts/prefabs/boneshard","title":"Boneshard","description":"Represents a collectible bone shard item used as crafting material and snowman decoration in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boneshard"},{"id":"game-scripts/prefabs/carnival_cannons","title":"Carnival Cannons","description":"A decorative and interactive prop used in Carnival events that fires visual FX when activated or supplied with a game token, and resets into a cooldown state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnival_cannons"},{"id":"game-scripts/components/carnivaldecor","title":"Carnivaldecor","description":"Tracks and reports the decorative value of an entity for carnival ranking systems by integrating with nearby CarnivalDecorRanker components.","permalink":"/dst-api-webdocs/docs/game-scripts/components/carnivaldecor"},{"id":"game-scripts/prefabs/carnivaldecor_lamp","title":"Carnivaldecor Lamp","description":"A reusable decorative light fixture that can be activated via manual interaction or token insertion, emitting light and playing animations while supporting save/load, hammering, and trading.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivaldecor_lamp"},{"id":"game-scripts/components/carnivaldecorranker","title":"Carnivaldecorranker","description":"Tracks and calculates the total decorative value and rank of carnival-themed decorations within proximity of an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/carnivaldecorranker"},{"id":"game-scripts/prefabs/carnivalgame_placementblocker","title":"Carnivalgame Placementblocker","description":"Provides a non-interactive, non-persistent placeholder entity used during carnival game setup to block placement and mark valid locations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnivalgame_placementblocker"},{"id":"game-scripts/prefabs/charcoal","title":"Charcoal","description":"A stackable consumable item that serves as fuel, food, bait, and a\u88c5\u9970 item in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/charcoal"},{"id":"game-scripts/prefabs/critterlab","title":"Critterlab","description":"Represents a decorative lab-themed critter den that emits idle sounds, plays animations, and supports prototyper functionality for crafting trees.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/critterlab"},{"id":"game-scripts/prefabs/decor_flowervase","title":"Decor Flowervase","description":"A decorative container component that holds and displays flowers, providing light, sanity effects, and inventory interactions when properly equipped.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/decor_flowervase"},{"id":"game-scripts/prefabs/decor_pictureframe","title":"Decor Pictureframe","description":"A decorative furniture item that can display a drawn image, supporting dynamic texture updates and state persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/decor_pictureframe"},{"id":"game-scripts/prefabs/endtable","title":"Endtable","description":"A decorative and functional structure that can hold flowers and emit light, with built-in durability and destruction handling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/endtable"},{"id":"game-scripts/components/furnituredecortaker","title":"Furnituredecortaker","description":"Manages the attachment and detachment of decorative items to furniture entities in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/components/furnituredecortaker"},{"id":"game-scripts/prefabs/gravestone","title":"Gravestone","description":"Manages the lifecycle, haunting mechanics, and ghost spawning behavior of a grave in the world, including seasonal flower decoration and upgrade stages.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gravestone"},{"id":"game-scripts/prefabs/grotto_waterfall_big","title":"Grotto Waterfall Big","description":"A decorative environment prefab representing a large grotto waterfall with looping animation and networked rendering.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/grotto_waterfall_big"},{"id":"game-scripts/prefabs/halloween_ornaments","title":"Halloween Ornaments","description":"Generates prefab instances for Halloween-themed decorative inventory items with floatable physics and limited fuel value.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/halloween_ornaments"},{"id":"game-scripts/prefabs/hermitcrab","title":"Hermitcrab","description":"This prefab defines the Hermit Crab (Pearl) NPC with friendship progression, trading mechanics, island decoration complaints, reward distribution, fishing activities, seasonal behaviors, and tea shop interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrab"},{"id":"game-scripts/prefabs/hermithouse_ornament","title":"Hermithouse Ornament","description":"A decorative inventory item that can be placed on the Hermithouse and emits sound and animation effects when interacted with.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermithouse_ornament"},{"id":"game-scripts/components/hull","title":"Hull","description":"Manages visual and logical attachment of boat-related accessories (plank, lip) and handles entity attachment offsets during boat placement.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hull"},{"id":"game-scripts/components/itemmimic","title":"Itemmimic","description":"Manages the transformation of an item mimic from an inert object into a hostile entity upon player interaction or time-based triggers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/itemmimic"},{"id":"game-scripts/prefabs/kitcoondecor","title":"Kitcoondecor","description":"Creates festive decoration prefabs for DST that function as cat toys, activatable structures, and hammerable objects, with burn and loot-drop behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/kitcoondecor"},{"id":"game-scripts/screens/mapscreen","title":"Mapscreen","description":"Manages the player\'s map interface, including minimap rendering, zoom controls, map decorations, and interaction handling via map actions.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/mapscreen"},{"id":"game-scripts/prefabs/monkeypillar","title":"Monkeypillar","description":"A decorative environmental prop that spawns in the Caves and exhibits periodic idle animations with random movement animations.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/monkeypillar"},{"id":"game-scripts/prefabs/moontree_blossom","title":"Moontree Blossom","description":"A perishable, stackable food item that can be dried into moon_tree_blossom_dried, used as a consumable item or decorative object.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moontree_blossom"},{"id":"game-scripts/prefabs/oceanvine_deco","title":"Oceanvine Deco","description":"A decorative, non-interactive foliage prop used in ocean/vine environments that fades based on distance and contributes no gameplay functionality.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanvine_deco"},{"id":"game-scripts/components/pearldecorationscore","title":"Pearldecorationscore","description":"Calculates and maintains a scoring value for pearl-based decorations based on nearby entities and terrain tiles, used for Hermit Crab home aesthetics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/pearldecorationscore"},{"id":"game-scripts/prefabs/petals","title":"Petals","description":"A plant-based consumable item that can be dried into a different product and haunts under certain conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/petals"},{"id":"game-scripts/map/static_layouts/pigguard_grass","title":"Pigguard Grass","description":"Defines static decorative layout data for a pigguard environment, including background tile patterns and foreground object placement.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/pigguard_grass"},{"id":"game-scripts/prefabs/pottedfern","title":"Pottedfern","description":"A decorative cave plant that can be placed in the world, destroyed with a hammer to yield loot, and burns or haunts players upon interaction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pottedfern"},{"id":"game-scripts/prefabs/quagmire_altar_statue","title":"Quagmire Altar Statue","description":"Helper function for creating decorative and environmental prefabs in the Quagmire and Park biomes with configurable animation banks, physics, and rotation behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_altar_statue"},{"id":"game-scripts/prefabs/quagmire_fern","title":"Quagmire Fern","description":"A decorative plant prefab for the Quagmire biome that provides no gameplay interaction beyond visual presence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_fern"},{"id":"game-scripts/prefabs/quagmire_portal","title":"Quagmire Portal","description":"A non-interactive environmental decoration prefab that renders the Quagmire portal structure and manages its camera focus behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_portal"},{"id":"game-scripts/prefabs/scorchedground","title":"Scorchedground","description":"Creates a background decorative ground effect with randomized animation and rotation for environmental immersion.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/scorchedground"},{"id":"game-scripts/map/static_layouts/sculptures_2","title":"Sculptures 2","description":"Defines a static layout for decorative and interactive sculptures in the game world using Tiled map data.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/sculptures_2"},{"id":"game-scripts/map/static_layouts/sculptures_3","title":"Sculptures 3","description":"A Tiled map file defining static layout data for sculptural decorations in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/sculptures_3"},{"id":"game-scripts/map/static_layouts/sculptures_4","title":"Sculptures 4","description":"Defines a static map layout containing sculpture placement data for the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/sculptures_4"},{"id":"game-scripts/map/static_layouts/sculptures_5","title":"Sculptures 5","description":"Defines a static map layout containing decorative sculptures and statues for in-game environments.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/sculptures_5"},{"id":"game-scripts/map/static_layouts/skeleton_construction","title":"Skeleton Construction","description":"A static map layout definition used to place pre-authored object instances in the game world, such as the skeleton and crafting materials.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/skeleton_construction"},{"id":"game-scripts/map/static_layouts/skeleton_entomologist","title":"Skeleton Entomologist","description":"A static map layout defining the layout and object placement for the Skeleton Entomologist room in the Caves.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/skeleton_entomologist"},{"id":"game-scripts/map/static_layouts/skeleton_lightfarmer","title":"Skeleton Lightfarmer","description":"Defines a static layout for a skeleton farmer decoration in the game world, containing background tiles and object placements.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/skeleton_lightfarmer"},{"id":"game-scripts/components/snowmandecoratable","title":"Snowmandecoratable","description":"Manages snowman decoration, stacking, hat placement, and state persistence for snowman entities in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/components/snowmandecoratable"},{"id":"game-scripts/screens/redux/snowmandecoratingscreen","title":"Snowmandecoratingscreen","description":"A UI screen that allows players to interactively decorate snowmen by placing decorative items onto snowball stacks using keyboard/controller input.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/snowmandecoratingscreen"},{"id":"game-scripts/prefabs/statue_marble","title":"Statue Marble","description":"A breakable decorative statue prefab that yields marbles and chess piece sketches upon mining, with type-specific behavior and save/load state management.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/statue_marble"},{"id":"game-scripts/prefabs/statuemaxwell","title":"Statuemaxwell","description":"A destructible decorative statue of Maxwell that yields chess pieces and marbles when mined, with special Charlie-related behavior under certain conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/statuemaxwell"},{"id":"game-scripts/map/static_layouts/rooms/room_residential/two","title":"Two","description":"Defines the tilemap layout for a residential room in the caves, including background tiles and decorative foreground objects.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/rooms/room_residential/two"},{"id":"game-scripts/components/vase","title":"Vase","description":"Manages flower placement, wilting behavior, and dynamic lighting for decorative vases in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/components/vase"},{"id":"game-scripts/components/vasedecoration","title":"Vasedecoration","description":"A placeholder component with no functional implementation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/vasedecoration"},{"id":"game-scripts/prefabs/vault_furniture","title":"Vault Furniture","description":"Defines two prefabs (vault_table_round and vault_stool) with variation management, decoration handling, and sittable/inspectable behavior for DST vault environments.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_furniture"},{"id":"game-scripts/prefabs/vault_pillar","title":"Vault Pillar","description":"Provides a decorative, interactive vault pillar entity with broken/capped states, optional relic attachment, and save/load persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_pillar"},{"id":"game-scripts/prefabs/vault_switch","title":"Vault Switch","description":"A decorative interactive switch component used in vault-related structures, supporting both standalone and base-mounted configurations with associated sound and animation logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_switch"},{"id":"game-scripts/prefabs/vaultrelic","title":"Vaultrelic","description":"A collectible decorative item that can be placed on furniture, decorated with flowers, and repaired; it provides ambient light and sanity benefits when freshly decorated.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vaultrelic"},{"id":"game-scripts/prefabs/wagstaff_items","title":"Wagstaff Items","description":"Defines prefabs for two wearable decorative items used by Wagstaff: a glove and a clipboard.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagstaff_items"},{"id":"game-scripts/prefabs/winter_tree","title":"Winter Tree","description":"Manages growth stages, decoration, lighting, and gift-giving behavior for seasonal winter trees during the Winters Feast event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winter_tree"}],"unlisted":false}}')}}]);